#include<bits/stdc++.h>
using namespace std;
const int MAXN=5005;
int a[MAXN];
int main(void){
	int t;
	for(cin>>t;t;t--){
		int n,t,m,x;
		cin>>n>>t>>m;
		for(int i=1;i<=n;i++)cin>>a[i],a[i]*=-1;
		for(int i=1;i<=m;i++)cin>>x,a[x]+=2;
		int ans=0;
		sort(a+1,a+n+1);
		for(int i=1;i<=n;i++){
			if(a[i]<0)ans++;
			else if(a[i]-t<0)t-=a[i]+1,ans++;
		}cout<<ans<<'\n';
	}
	return false;
}
